import{_ as e,c as i,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"更新日誌：版本歷史和功能變更 | Agent App Factory","description":"了解 Agent App Factory 的版本更新歷史、功能變更、bug 修復和重大改進。本頁面詳細記錄從 1.0.0 版本開始的完整變更歷史，包括 7 階段流水線系統、Sisyphus 調度器、權限管理、上下文優化和失敗處理策略等核心功能和改進。","frontmatter":{"title":"更新日誌：版本歷史和功能變更 | Agent App Factory","sidebarTitle":"更新日誌","subtitle":"更新日誌：版本歷史和功能變更 | Agent App Factory","description":"了解 Agent App Factory 的版本更新歷史、功能變更、bug 修復和重大改進。本頁面詳細記錄從 1.0.0 版本開始的完整變更歷史，包括 7 階段流水線系統、Sisyphus 調度器、權限管理、上下文優化和失敗處理策略等核心功能和改進。","tags":["更新日誌","版本歷史"],"prerequisite":[],"order":250},"headers":[],"relativePath":"zh-tw/hyz1992/agent-app-factory/changelog/release-notes/index.md","filePath":"zh-tw/hyz1992/agent-app-factory/changelog/release-notes/index.md"}'),l={name:"zh-tw/hyz1992/agent-app-factory/changelog/release-notes/index.md"};function o(n,t,d,c,s,g){return r(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="更新日誌" tabindex="-1">更新日誌 <a class="header-anchor" href="#更新日誌" aria-label="Permalink to &quot;更新日誌&quot;">​</a></h1><p>本頁面記錄 Agent App Factory 的版本更新歷史，包括新增功能、改進、bug 修復和破壞性變更。</p><p>格式遵循 <a href="https://keepachangelog.com/zh-CN/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> 規範，版本號遵循 <a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">Semantic Versioning</a>。</p><h2 id="_1-0-0-2024-01-29" tabindex="-1">[1.0.0] - 2024-01-29 <a class="header-anchor" href="#_1-0-0-2024-01-29" aria-label="Permalink to &quot;[1.0.0] - 2024-01-29&quot;">​</a></h2><h3 id="新增" tabindex="-1">新增 <a class="header-anchor" href="#新增" aria-label="Permalink to &quot;新增&quot;">​</a></h3><p><strong>核心功能</strong></p><ul><li><p><strong>7 階段流水線系統</strong>：從想法到可執行應用的完整自動化流程</p><ul><li>Bootstrap - 結構化產品想法（input/idea.md）</li><li>PRD - 生成產品需求文檔（artifacts/prd/prd.md）</li><li>UI - 設計 UI 結構和可預覽原型（artifacts/ui/）</li><li>Tech - 設計技術架構和 Prisma 資料模型（artifacts/tech/）</li><li>Code - 生成前後端代碼（artifacts/backend/, artifacts/client/）</li><li>Validation - 驗證代碼品質（artifacts/validation/report.md）</li><li>Preview - 生成部署指南（artifacts/preview/README.md）</li></ul></li><li><p><strong>Sisyphus 調度器</strong>：流水線核心控制組件</p><ul><li>按順序執行 pipeline.yaml 定義的各個 Stage</li><li>驗證每個階段的輸入/輸出和退出條件</li><li>維護流水線狀態（.factory/state.json）</li><li>執行權限檢查，防止 Agent 越權讀寫</li><li>根據失敗策略處理異常情況</li><li>在每個檢查點暫停，等待人工確認後繼續</li></ul></li></ul><p><strong>CLI 工具</strong></p><ul><li><code>factory init</code> - 初始化 Factory 專案</li><li><code>factory run [stage]</code> - 執行流水線（從當前或指定階段）</li><li><code>factory continue</code> - 在新會話中繼續執行（節省 Token）</li><li><code>factory status</code> - 查看當前專案狀態</li><li><code>factory list</code> - 列出所有 Factory 專案</li><li><code>factory reset</code> - 重置當前專案狀態</li></ul><p><strong>權限與安全</strong></p><ul><li><strong>能力邊界矩陣</strong>（capability.matrix.md）：定義每個 Agent 嚴格的讀寫權限 <ul><li>每個 Agent 只能存取已授權目錄</li><li>越權寫入檔案移至 artifacts/_untrusted/</li><li>失敗後自動暫停流水線，等待人工介入</li></ul></li></ul><p><strong>上下文優化</strong></p><ul><li><strong>分會話執行</strong>：每個階段在新會話中執行 <ul><li>避免上下文累積，節省 Token</li><li>支援中斷恢復</li><li>適用於所有 AI 助手（Claude Code、OpenCode、Cursor）</li></ul></li></ul><p><strong>失敗處理策略</strong></p><ul><li>自動重試機制：每個階段允許重試一次</li><li>失敗歸檔：失敗的產物移至 artifacts/_failed/</li><li>回滾機制：回滾到最近成功檢查點</li><li>人工介入：連續失敗兩次後暫停</li></ul><p><strong>品質保證</strong></p><ul><li><p><strong>代碼規範</strong>（code-standards.md）</p><ul><li>TypeScript 編碼規範和最佳實踐</li><li>檔案結構和命名約定</li><li>註解和文檔要求</li><li>Git 提交訊息規範（Conventional Commits）</li></ul></li><li><p><strong>錯誤碼規範</strong>（error-codes.md）</p><ul><li>統一錯誤碼結構：[MODULE]<em>[ERROR_TYPE]</em>[SPECIFIC]</li><li>標準錯誤類型：VALIDATION, NOT_FOUND, FORBIDDEN, CONFLICT, INTERNAL_ERROR</li><li>前後端錯誤碼映射和用戶友善提示</li></ul></li></ul><p><strong>Changelog 管理</strong></p><ul><li>遵循 Keep a Changelog 格式</li><li>與 Conventional Commits 整合</li><li>自動化工具支援：conventional-changelog-cli, release-it</li></ul><p><strong>配置模板</strong></p><ul><li>CI/CD 配置（GitHub Actions）</li><li>Git Hooks 配置（Husky）</li></ul><p><strong>生成的應用特性</strong></p><ul><li>完整的前後端代碼（Express + Prisma + React Native）</li><li>單元測試和整合測試（Vitest + Jest）</li><li>API 文檔（Swagger/OpenAPI）</li><li>資料庫種子資料</li><li>Docker 部署配置</li><li>錯誤處理和日誌監控</li><li>效能優化和安全檢查</li></ul><h3 id="改進" tabindex="-1">改進 <a class="header-anchor" href="#改進" aria-label="Permalink to &quot;改進&quot;">​</a></h3><p><strong>MVP 聚焦</strong></p><ul><li>明確列出非目標（Non-Goals），防止範圍蔓延</li><li>頁面數量限制在 3 頁以內</li><li>專注核心功能，避免過度設計</li></ul><p><strong>職責分離</strong></p><ul><li>每個 Agent 只負責自己的領域，不越界</li><li>PRD 不包含技術細節，Tech 不涉及 UI 設計</li><li>Code Agent 嚴格按照 UI Schema 和 Tech 設計實作</li></ul><p><strong>可驗證性</strong></p><ul><li>每個階段定義明確的 exit_criteria</li><li>所有功能可測試、可本地執行</li><li>產物必須結構化、可被下游消費</li></ul><h3 id="技術堆疊" tabindex="-1">技術堆疊 <a class="header-anchor" href="#技術堆疊" aria-label="Permalink to &quot;技術堆疊&quot;">​</a></h3><p><strong>CLI 工具</strong></p><ul><li>Node.js &gt;= 16.0.0</li><li>Commander.js - 命令列框架</li><li>Chalk - 彩色終端輸出</li><li>Ora - 進度指示器</li><li>Inquirer - 互動式命令列</li><li>fs-extra - 檔案系統操作</li><li>YAML - YAML 解析</li></ul><p><strong>生成的應用</strong></p><ul><li>後端：Node.js + Express + Prisma + TypeScript + Vitest</li><li>前端：React Native + Expo + TypeScript + Jest + React Testing Library</li><li>部署：Docker + GitHub Actions</li></ul><h3 id="依賴" tabindex="-1">依賴 <a class="header-anchor" href="#依賴" aria-label="Permalink to &quot;依賴&quot;">​</a></h3><ul><li><code>chalk@^4.1.2</code> - 終端顏色樣式</li><li><code>commander@^11.0.0</code> - 命令列參數解析</li><li><code>fs-extra@^11.1.1</code> - 檔案系統擴展</li><li><code>inquirer@^8.2.5</code> - 互動式命令列</li><li><code>ora@^5.4.1</code> - 優雅的終端載入器</li><li><code>yaml@^2.3.4</code> - YAML 解析和序列化</li></ul><h2 id="版本說明" tabindex="-1">版本說明 <a class="header-anchor" href="#版本說明" aria-label="Permalink to &quot;版本說明&quot;">​</a></h2><h3 id="semantic-versioning" tabindex="-1">Semantic Versioning <a class="header-anchor" href="#semantic-versioning" aria-label="Permalink to &quot;Semantic Versioning&quot;">​</a></h3><p>本專案遵循 <a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">Semantic Versioning</a> 版本號格式：MAJOR.MINOR.PATCH</p><ul><li><strong>MAJOR</strong>：不相容的 API 變更</li><li><strong>MINOR</strong>：向後相容的新增功能</li><li><strong>PATCH</strong>：向後相容的 bug 修復</li></ul><h3 id="變更類型" tabindex="-1">變更類型 <a class="header-anchor" href="#變更類型" aria-label="Permalink to &quot;變更類型&quot;">​</a></h3><ul><li><strong>新增</strong>（Added）：新功能</li><li><strong>變更</strong>（Changed）：現有功能的變更</li><li><strong>棄用</strong>（Deprecated）：即將移除的功能</li><li><strong>移除</strong>（Removed）：已移除的功能</li><li><strong>修復</strong>（Fixed）：bug 修復</li><li><strong>安全</strong>（Security）：安全修復</li></ul><h2 id="相關資源" tabindex="-1">相關資源 <a class="header-anchor" href="#相關資源" aria-label="Permalink to &quot;相關資源&quot;">​</a></h2><ul><li><a href="https://github.com/hyz1992/agent-app-factory/releases" target="_blank" rel="noreferrer">GitHub Releases</a> - 官方發布頁面</li><li><a href="https://github.com/hyz1992/agent-app-factory" target="_blank" rel="noreferrer">專案倉庫</a> - 源代碼</li><li><a href="https://github.com/hyz1992/agent-app-factory/issues" target="_blank" rel="noreferrer">問題追蹤</a> - 反饋問題和建議</li><li><a href="https://github.com/hyz1992/agent-app-factory/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">貢獻指南</a> - 如何貢獻</li></ul><hr><h2 id="附錄-源碼參考" tabindex="-1">附錄：源碼參考 <a class="header-anchor" href="#附錄-源碼參考" aria-label="Permalink to &quot;附錄：源碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看源碼位置</strong></summary><blockquote><p>更新時間：2024-01-29</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>package.json</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/package.json" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-52</td></tr><tr><td>CLI 入口</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/bin/factory.js" target="_blank" rel="noreferrer"><code>cli/bin/factory.js</code></a></td><td>1-123</td></tr><tr><td>初始化命令</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/init.js" target="_blank" rel="noreferrer"><code>cli/commands/init.js</code></a></td><td>1-427</td></tr><tr><td>執行命令</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/run.js" target="_blank" rel="noreferrer"><code>cli/commands/run.js</code></a></td><td>1-294</td></tr><tr><td>繼續命令</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-87</td></tr><tr><td>流水線定義</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>1-87</td></tr><tr><td>調度器定義</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-301</td></tr><tr><td>權限矩陣</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/capability.matrix.md" target="_blank" rel="noreferrer"><code>policies/capability.matrix.md</code></a></td><td>1-44</td></tr><tr><td>失敗策略</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>1-200</td></tr><tr><td>代碼規範</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>1-287</td></tr><tr><td>錯誤碼規範</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/error-codes.md" target="_blank" rel="noreferrer"><code>policies/error-codes.md</code></a></td><td>1-134</td></tr><tr><td>Changelog 規範</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/changelog.md" target="_blank" rel="noreferrer"><code>policies/changelog.md</code></a></td><td>1-87</td></tr></tbody></table><p><strong>關鍵版本資訊</strong>：</p><ul><li><code>version = &quot;1.0.0&quot;</code>：初始發布版本</li><li><code>engines.node = &quot;&gt;=16.0.0&quot;</code>：最低 Node.js 版本要求</li></ul><p><strong>依賴版本</strong>：</p><ul><li><code>chalk@^4.1.2</code>：終端顏色樣式</li><li><code>commander@^11.0.0</code>：命令列參數解析</li><li><code>fs-extra@^11.1.1</code>：檔案系統擴展</li><li><code>inquirer@^8.2.5</code>：互動式命令列</li><li><code>ora@^5.4.1</code>：優雅的終端載入器</li><li><code>yaml@^2.3.4</code>：YAML 解析和序列化</li></ul></details>',48)])])}const u=e(l,[["render",o]]);export{h as __pageData,u as default};
